    {
        String baseurl = m_pathPrefix;

        if( absolute ) baseurl = m_engine.getBaseURL() + "/";

        baseptrn = TextUtil.replaceString( baseptrn, "%u", baseurl );
        baseptrn = TextUtil.replaceString( baseptrn, "%U", m_engine.getBaseURL() );
